export const getGetUserReflectionsUrl = (
  userId: string,
  params?: GetUserReflectionsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/users/${userId}/reflections?${stringifiedParams}`
    : `/users/${userId}/reflections`;
};

export const getUserReflections = async (
  userId: string,
  params?: GetUserReflectionsParams,
  options?: RequestInit,
): Promise<getUserReflectionsResponse> => {
  return api<getUserReflectionsResponse>(
    getGetUserReflectionsUrl(userId, params),
    {
      ...options,
      method: 'GET',
    },
  );
};

